package iut.gon.bomberman.client.view;

import iut.gon.bomberman.common.model.labyrinthe.CellType;
import iut.gon.bomberman.common.model.labyrinthe.Labyrinthe;
import iut.gon.bomberman.common.model.player.Joueur;
import javafx.scene.canvas.GraphicsContext;
import javafx.scene.image.Image;
import javafx.scene.paint.Color;

public class LabRenderer {
    private static final int TILE_SIZE = 32;

    private final Image wallImg = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/block_04.png"));
    private final Image destructibleImg = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/block_06.png"));
    private final Image groundImg = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/ground_01.png"));

    private final Image playerSprite = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/8/E_0.png"));

    public void draw(GraphicsContext gc, Labyrinthe lab) {
        for (int x = 0; x < lab.getWidth(); x++) {
            for (int y = 0; y < lab.getHeight(); y++) {
                CellType type = lab.getCell(x,y);

                gc.drawImage(groundImg, x * TILE_SIZE, y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
                if (type == CellType.WALL) {
                    gc.drawImage(wallImg, x * TILE_SIZE, y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
                } else if (type == CellType.DESTRUCTIBLE) {
                    gc.drawImage(destructibleImg, x * TILE_SIZE, y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
                }
            }
        }
    }

    public void drawPlayer(GraphicsContext gc, Joueur joueur) {
        if (joueur == null) {
            return;
        }
        double screenX = joueur.getX() * TILE_SIZE;
        double screenY = joueur.getY() * TILE_SIZE;
        gc.drawImage(playerSprite, screenX, screenY, TILE_SIZE, TILE_SIZE);
    }
}

package iut.gon.bomberman.client.view;

import iut.gon.bomberman.common.model.labyrinthe.CellType;
import iut.gon.bomberman.common.model.labyrinthe.Labyrinthe;
import iut.gon.bomberman.common.model.player.Joueur;
import javafx.scene.canvas.GraphicsContext;
import javafx.scene.image.Image;
import javafx.scene.paint.Color;

import java.util.HashMap;
import java.util.Map;

public class LabRenderer {
    private static final int TILE_SIZE = 32;

    // Animation parameters
    private static final int FRAME_DURATION = 10; // frames par image (60 FPS / 6 = 10 images/sec)
    private int frameCounter = 0;
    private int currentFrame = 0;
    private static final int FRAMES_PER_DIRECTION = 4; // Nombre d'images par direction

    private final Image wallImg = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/block_04.png"));
    private final Image destructibleImg = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/block_06.png"));
    private final Image groundImg = new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/ground_01.png"));

    // Sprite sheets pour les directions
    private final Map<String, Image[]> playerAnimations = new HashMap<>();

    private String currentDirection = "E"; // Direction actuelle (E, W, N, S)

    public LabRenderer() {
        loadAnimations();
    }

    /**
     * Charger les images d'animation pour chaque direction
     */
    private void loadAnimations() {
        // Exemple pour direction Est
        playerAnimations.put("E", new Image[]{
            new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/8/E_0.png")),
            new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/8/E_0.png")),
            new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/8/E_0.png")),
            new Image(getClass().getResourceAsStream("/iut/gon/bomberman/client/assets/8/E_0.png"))
        });

        // Vous pouvez ajouter d'autres directions si vous avez les sprites
        playerAnimations.put("W", playerAnimations.get("E"));
        playerAnimations.put("N", playerAnimations.get("E"));
        playerAnimations.put("S", playerAnimations.get("E"));
    }

    public void draw(GraphicsContext gc, Labyrinthe lab) {
        for (int x = 0; x < lab.getWidth(); x++) {
            for (int y = 0; y < lab.getHeight(); y++) {
                CellType type = lab.getCell(x,y);

                gc.drawImage(groundImg, x * TILE_SIZE, y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
                if (type == CellType.WALL) {
                    gc.drawImage(wallImg, x * TILE_SIZE, y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
                } else if (type == CellType.DESTRUCTIBLE) {
                    gc.drawImage(destructibleImg, x * TILE_SIZE, y * TILE_SIZE, TILE_SIZE, TILE_SIZE);
                }
            }
        }
    }

    /**
     * Mettre à jour l'animation du joueur
     */
    public void updateAnimation(double dx, double dy) {
        // Déterminer la direction basée sur le mouvement
        if (dx > 0) {
            currentDirection = "E";
        } else if (dx < 0) {
            currentDirection = "W";
        } else if (dy < 0) {
            currentDirection = "N";
        } else if (dy > 0) {
            currentDirection = "S";
        }

        // Boucle d'animation
        frameCounter++;
        if (frameCounter >= FRAME_DURATION) {
            frameCounter = 0;
            currentFrame = (currentFrame + 1) % FRAMES_PER_DIRECTION;
        }
    }

    /**
     * Réinitialiser le compteur d'animation (quand le joueur s'arrête)
     */
    public void stopAnimation() {
        frameCounter = 0;
        currentFrame = 0;
    }

    public void drawPlayer(GraphicsContext gc, Joueur joueur) {
        if (joueur == null) {
            return;
        }
        double screenX = joueur.getX() * TILE_SIZE;
        double screenY = joueur.getY() * TILE_SIZE;

        // Obtenir l'image animée
        Image[] frames = playerAnimations.get(currentDirection);
        if (frames != null && frames.length > 0) {
            Image frame = frames[currentFrame];
            gc.drawImage(frame, screenX, screenY, TILE_SIZE, TILE_SIZE);
        }
    }
}
